+                                        cursor_position:
+                                            mux::renderable::StableCursorPosition::default(),
+                                        dimensions: mux::renderable::RenderableDimensions {
+                                            cols: 80,
+                                            viewport_rows: 24,
+                                            scrollback_rows: 0,
+                                            physical_top: 0,
+                                            scrollback_top: 0,
+                                            dpi: 96,
+                                            pixel_width: 0,
+                                            pixel_height: 0,
