+                                        title: format!("pane-{}", request.pane_id),
+                                        working_dir: None,
+                                        bonus_lines: Vec::new().into(),
+                                        input_serial: None,
+                                        seqno: request.pane_id,
+                                    },
+                                );
+                                let mut out = Vec::new();
+                                response
+                                    .encode(&mut out, decoded.serial)
+                                    .expect("encode response");
+                                stream.write_all(&out).await.expect("write response");
+                            }
+                            _ => {}
+                        }
+                    }
+                }
